```python
import random

def f(x):
    return x**2 - 2  # Example function f(x) = x^2 - 2

def bisect(f, a, b, tol):
    if f(a) * f(b) >= 0:
        print("Bisection method fails.")
        return None
    c = a
    while (b - a) / 2 > tol:
        c = (a + b) / 2
        if f(c) == 0.0:
            break
        if f(c) * f(a) < 0:
            b = c
        else:
            a = c
    return c

def monte_carlo_refine(f, target, x_val, tol, n_samples):
    count = 0
    for _ in range(n_samples):
        x = random.uniform(x_val - tol, x_val + tol)
        if abs(f(x) - target) <= tol:
            count += 1
    return x_val, count / n_samples

def find_root(f, a, b, tol, n_samples, n_decimal_places):
    root = bisect(f, a, b, tol)
    if root is not None:
        root_str = f"{root:.{n_decimal_places}f}"
        print(f"Root found at: {root_str}")
        return root_str
    else:
        print("Bisection method failed to find a root within the given interval.")
        return None

